import sqlite3
from flask import Flask, render_template, request, redirect, url_for, session, g
import os
from config import Config

app = Flask(__name__)
app.config.from_object(Config)

def get_db():
    db = getattr(g, '_database', None)
    if db is None:
        db = g._database = sqlite3.connect(Config.DATABASE_PATH)
        db.row_factory = sqlite3.Row
    return db

@app.teardown_appcontext
def close_connection(exception):
    db = getattr(g, '_database', None)
    if db is not None:
        db.close()

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')

        db = get_db()
        user = db.execute('SELECT * FROM users WHERE username = ? AND password = ?', (username, password)).fetchone()

        if user:
            session['user_id'] = user['id']
            session['username'] = user['username']
            return redirect(url_for('dashboard'))
        return render_template('login.html', error="Invalid credentials")
    return render_template('login.html')

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

@app.route('/dashboard')
def dashboard():
    if 'user_id' not in session:
        return redirect(url_for('login'))
    return render_template('dashboard.html')

@app.route('/profile')
def profile():
    if 'user_id' not in session:
        return redirect(url_for('login'))

    uid = request.args.get('uid', session['user_id'])
    db = get_db()
    user_profile = db.execute('SELECT username, role FROM users WHERE id = ?', (uid,)).fetchone()
    return render_template('profile.html', profile=user_profile)

@app.route('/search')
def search():
    if 'user_id' not in session:
        return redirect(url_for('login'))

    tracking_id = request.args.get('tracking_id', '')
    results = []

    if tracking_id:
        # SECURITY FILTER: Removes spaces to 'prevent' SQLi
        sanitized_id = tracking_id.replace(' ', '')

        # VULNERABILITY: String concatenation after weak filtering
        query = f"SELECT id, tracking_id, destination, status FROM shipments WHERE tracking_id = '{sanitized_id}'"

        db = get_db()
        try:
            cursor = db.cursor()
            results = cursor.execute(query).fetchall()
        except Exception as e:
            return render_template('dashboard.html', error=f"Database Error: {str(e)}")

    return render_template('dashboard.html', results=results, query=tracking_id)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

